// ============================================================================
// useTokens Composable
// ============================================================================

export function useTokens() {
  const tokens = ref<TokensObject>(tokensData);

  // Get a specific token value by dot-notation path
  const getToken = (path: string): any => {
    return path.split('.').reduce((obj: any, key: string) => obj?.[key], tokens.value);
  };

  // Get all tokens
  const getAllTokens = computed(() => tokens.value);

  return {
    tokens: getAllTokens,
    getToken,
  };
}
